class Solution {
public:
    int countKReducibleNumbers(string s, int k) {
        const int MOD = 1e9 + 7;
        int n = s.size();
        int target = 0;
        for (char c : s) target = (target << 1) + (c - '0');
        vector<int> dp(k + 1, 0);
        dp[0] = 1;
        int res = 0;
        for (int i = 1; i < target; ++i) {
            int cnt = __builtin_popcount(i);
            for (int j = k; j > 0; --j) {
                dp[j] = (dp[j] + dp[j - 1] * (cnt == i)) % MOD;
            }
            if (cnt == i) dp[0] = (dp[0] + 1) % MOD;
            if (i < target && dp[k]) res = (res + 1) % MOD;
        }
        return res;
    }
};
```
